p.m:
\displaystyle{\begin{aligned}
   8\div \frac{4}{5} 
       \amp = \frac{8}{1} \div \frac{4}{5} \\
       \amp = \frac{8}{1} \cdot \frac{5}{4} \amp \hbox{We can divide 8 and 4 by 4 and made those two values smaller.}\\
       \amp = \frac{2}{1}\cdot\frac{5}{1} \\
       \amp = \frac{2\cdot5}{1 \cdot 1} \\
       \amp = 10
\end{aligned}
    }
